// ── Roles ──

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum Role {
    Supporter,
    ProjectManager,
    FinanceReviewer,
    Administrator,
}

impl Role {
    pub fn as_str(&self) -> &'static str {
        match self {
            Role::Supporter => "supporter",
            Role::ProjectManager => "project_manager",
            Role::FinanceReviewer => "finance_reviewer",
            Role::Administrator => "administrator",
        }
    }

    pub fn from_str(s: &str) -> Option<Self> {
        match s {
            "supporter" => Some(Role::Supporter),
            "project_manager" => Some(Role::ProjectManager),
            "finance_reviewer" => Some(Role::FinanceReviewer),
            "administrator" => Some(Role::Administrator),
            _ => None,
        }
    }
}

// ── Project Status ──

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ProjectStatus {
    Draft,
    Active,
    Funded,
    Closed,
    Unpublished,
}

impl ProjectStatus {
    pub fn as_str(&self) -> &'static str {
        match self {
            ProjectStatus::Draft => "draft",
            ProjectStatus::Active => "active",
            ProjectStatus::Funded => "funded",
            ProjectStatus::Closed => "closed",
            ProjectStatus::Unpublished => "unpublished",
        }
    }

    pub fn from_str(s: &str) -> Option<Self> {
        match s {
            "draft" => Some(ProjectStatus::Draft),
            "active" => Some(ProjectStatus::Active),
            "funded" => Some(ProjectStatus::Funded),
            "closed" => Some(ProjectStatus::Closed),
            "unpublished" => Some(ProjectStatus::Unpublished),
            _ => None,
        }
    }
}

// ── Disclosure Status ──

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum DisclosureStatus {
    Pending,
    Approved,
    Rejected,
}

impl DisclosureStatus {
    pub fn as_str(&self) -> &'static str {
        match self {
            DisclosureStatus::Pending => "pending",
            DisclosureStatus::Approved => "approved",
            DisclosureStatus::Rejected => "rejected",
        }
    }

    pub fn from_str(s: &str) -> Option<Self> {
        match s {
            "pending" => Some(DisclosureStatus::Pending),
            "approved" => Some(DisclosureStatus::Approved),
            "rejected" => Some(DisclosureStatus::Rejected),
            _ => None,
        }
    }
}

// ── Data Transfer Objects ──

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UserProfile {
    pub id: String,
    pub email: String,
    pub display_name: String,
    pub role: Role,
    pub dnd_start: String,
    pub dnd_end: String,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProjectSummary {
    pub id: String,
    pub title: String,
    pub cause: String,
    pub zip_code: String,
    pub status: ProjectStatus,
    pub goal_cents: i64,
    pub raised_cents: i64,
    pub spent_cents: i64,
    pub manager_name: String,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProjectDetail {
    pub id: String,
    pub title: String,
    pub description: String,
    pub cause: String,
    pub zip_code: String,
    pub status: ProjectStatus,
    pub goal_cents: i64,
    pub raised_cents: i64,
    pub spent_cents: i64,
    pub manager_id: String,
    pub manager_name: String,
    pub budget_lines: Vec<BudgetLine>,
    pub updates: Vec<SpendingUpdate>,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BudgetLine {
    pub id: String,
    pub project_id: String,
    pub name: String,
    pub allocated_cents: i64,
    pub spent_cents: i64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SpendingUpdate {
    pub id: String,
    pub project_id: String,
    pub title: String,
    pub body: String,
    pub author_name: String,
    pub like_count: i64,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DonationRecord {
    pub id: String,
    pub pledge_number: String,
    pub project_id: String,
    pub project_title: String,
    pub donor_id: String,
    pub amount_cents: i64,
    pub budget_line_id: Option<String>,
    pub budget_line_name: Option<String>,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExpenseRecord {
    pub id: String,
    pub project_id: String,
    pub budget_line_id: String,
    pub budget_line_name: String,
    pub amount_cents: i64,
    pub description: String,
    pub receipt_url: Option<String>,
    pub disclosure_status: DisclosureStatus,
    pub reviewer_note: Option<String>,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Comment {
    pub id: String,
    pub project_id: String,
    pub author_id: String,
    pub author_name: String,
    pub body: String,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Notification {
    pub id: String,
    pub user_id: String,
    pub title: String,
    pub body: String,
    pub is_read: bool,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Ticket {
    pub id: String,
    pub project_id: String,
    pub submitter_id: String,
    pub submitter_name: String,
    pub subject: String,
    pub body: String,
    pub status: String,
    pub response: Option<String>,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OpsLogEntry {
    pub id: String,
    pub actor_id: String,
    pub actor_name: String,
    pub action: String,
    pub detail: String,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DashboardStats {
    pub gmv_cents: i64,
    pub total_donations: i64,
    pub unique_donors: i64,
    pub average_donation_cents: i64,
    pub repeat_donor_rate: f64,
    pub conversion_rate: f64,
}

// ── Request / Response DTOs ──

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RegisterRequest {
    pub email: String,
    pub password: String,
    pub display_name: String,
    pub role: Role,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LoginRequest {
    pub email: String,
    pub password: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AuthResponse {
    pub token: String,
    pub user: UserProfile,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CreateProjectRequest {
    pub title: String,
    pub description: String,
    pub cause: String,
    pub zip_code: String,
    pub goal_cents: i64,
    pub budget_lines: Vec<CreateBudgetLine>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CreateBudgetLine {
    pub name: String,
    pub allocated_cents: i64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DonateRequest {
    pub project_id: String,
    pub amount_cents: i64,
    pub budget_line_id: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DonateResponse {
    pub donation: DonationRecord,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PostUpdateRequest {
    pub project_id: String,
    pub title: String,
    pub body: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RecordExpenseRequest {
    pub project_id: String,
    pub budget_line_id: String,
    pub amount_cents: i64,
    pub description: String,
    pub receipt_data: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReviewExpenseRequest {
    pub expense_id: String,
    pub approved: bool,
    pub note: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CreateCommentRequest {
    pub project_id: String,
    pub body: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SubmitTicketRequest {
    pub project_id: String,
    pub subject: String,
    pub body: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RespondTicketRequest {
    pub ticket_id: String,
    pub response: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProjectFilter {
    pub cause: Option<String>,
    pub status: Option<String>,
    pub zip_code: Option<String>,
    pub search: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DateRange {
    pub from: Option<String>,
    pub to: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DndSettings {
    pub dnd_start: String,
    pub dnd_end: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SensitiveActionConfirm {
    pub password: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ApiError {
    pub error: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ApiSuccess {
    pub message: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PaginatedResponse<T> {
    pub items: Vec<T>,
    pub total: i64,
    pub page: i64,
    pub per_page: i64,
}
"}

