// ── Dashboard stats ──

pub fn get_dashboard_stats(db: &DbPool, from: Option<&str>, to: Option<&str>) -> common::DashboardStats {
    let conn = db.lock();
    let date_filter = match (from, to) {
        (Some(f), Some(t)) => format!("AND d.created_at BETWEEN '{}' AND '{}'", f, t),
        (Some(f), None) => format!("AND d.created_at >= '{}'", f),
        (None, Some(t)) => format!("AND d.created_at <= '{}'", t),
        (None, None) => String::new(),
    };

    let gmv: i64 = conn
        .query_row(
            &format!("SELECT COALESCE(SUM(amount_cents), 0) FROM donations d WHERE 1=1 {}", date_filter),
            [],
            |row| row.get(0),
        )
        .unwrap_or(0);

    let total_donations: i64 = conn
        .query_row(
            &format!("SELECT COUNT(*) FROM donations d WHERE 1=1 {}", date_filter),
            [],
            |row| row.get(0),
        )
        .unwrap_or(0);

    let unique_donors: i64 = conn
        .query_row(
            &format!("SELECT COUNT(DISTINCT donor_id) FROM donations d WHERE 1=1 {}", date_filter),
            [],
            |row| row.get(0),
        )
        .unwrap_or(0);

    let average_donation_cents = if total_donations > 0 {
        gmv / total_donations
    } else {
        0
    };

    let repeat_donors: i64 = conn
        .query_row(
            &format!(
                "SELECT COUNT(*) FROM (SELECT donor_id FROM donations d WHERE 1=1 {} GROUP BY donor_id HAVING COUNT(*) > 1)",
                date_filter
            ),
            [],
            |row| row.get(0),
        )
        .unwrap_or(0);

    let repeat_donor_rate = if unique_donors > 0 {
        repeat_donors as f64 / unique_donors as f64
    } else {
        0.0
    };

    let total_users: i64 = conn
        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
        .unwrap_or(1);

    let conversion_rate = if total_users > 0 {
        unique_donors as f64 / total_users as f64
    } else {
        0.0
    };

    common::DashboardStats {
        gmv_cents: gmv,
        total_donations,
        unique_donors,
        average_donation_cents,
        repeat_donor_rate,
        conversion_rate,
    }
}

// ── CSV Export helpers ──

pub fn export_donations_csv(db: &DbPool, from: Option<&str>, to: Option<&str>) -> String {
    let conn = db.lock();
    let date_filter = match (from, to) {
        (Some(f), Some(t)) => format!("WHERE d.created_at BETWEEN '{}' AND '{}'", f, t),
        (Some(f), None) => format!("WHERE d.created_at >= '{}'", f),
        (None, Some(t)) => format!("WHERE d.created_at <= '{}'", t),
        (None, None) => String::new(),
    };

    let query = format!(
        "SELECT d.pledge_number, p.title, \
         SUBSTR(u.display_name, 1, 1) || '***' AS masked_name, \
         d.amount_cents, bl.name, d.created_at \
         FROM donations d \
         JOIN projects p ON d.project_id = p.id \
         JOIN users u ON d.donor_id = u.id \
         LEFT JOIN budget_lines bl ON d.budget_line_id = bl.id \
         {} ORDER BY d.created_at DESC",
        date_filter
    );

    let mut stmt = conn.prepare(&query).unwrap();
    let mut wtr = csv::Writer::from_writer(Vec::new());
    wtr.write_record(["Pledge#", "Project", "Donor (masked)", "Amount (cents)", "Budget Line", "Date"])
        .unwrap();
    let rows = stmt
        .query_map([], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, String>(1)?,
                row.get::<_, String>(2)?,
                row.get::<_, i64>(3)?,
                row.get::<_, Option<String>>(4)?,
                row.get::<_, String>(5)?,
            ))
        })
        .unwrap();
    for r in rows.flatten() {
        wtr.write_record(&[
            r.0,
            r.1,
            r.2,
            r.3.to_string(),
            r.4.unwrap_or_default(),
            r.5,
        ])
        .unwrap();
    }
    String::from_utf8(wtr.into_inner().unwrap()).unwrap_or_default()
}
