    db::append_ops_log(
        &state.db,
        &auth.user_id,
        &user.display_name,
        "create_project",
        &format!("Created project: {}", req.title),
    );

    let detail = db::get_project_detail(&state.db, &project_id).unwrap();
    Ok(Json(detail))
