    pub fn logout(&self) {
        gloo_storage::LocalStorage::delete("auth_token");
        gloo_storage::LocalStorage::delete("current_user");
        (self.set_token)(None);
        (self.set_user)(None);
    }

    pub fn is_logged_in(&self) -> bool {
        (self.token)().is_some()
    }

    pub fn get_token(&self) -> Option<String> {
        (self.token)()
    }
}
"}

