{"file_path": "/home/eren/Documents/task4/Fund_Transparency/crates/web/src/pages/login.rs", "content": "use leptos::*;
use leptos_router::*;

use crate::api;
use crate::state::AuthState;

#[component]
pub fn LoginPage() -> impl IntoView {
    let auth = use_context::<AuthState>().unwrap();
    let (email, set_email) = create_signal(String::new());
    let (password, set_password) = create_signal(String::new());
    let (error, set_error) = create_signal(Option::<String>::None);
    let navigate = use_navigate();

    let on_submit = move |ev: leptos::ev::SubmitEvent| {
        ev.prevent_default();
        let email = email.get();
        let password = password.get();
        let navigate = navigate.clone();
        spawn_local(async move {
            match api::login(&email, &password).await {
                Ok(resp) => {
                    auth.login(resp.token, resp.user);
                    navigate("/projects", Default::default());
                }
                Err(e) => set_error(Some(e)),
            }
        });
    };

    view! {
        <div class="auth-page">
            <h2>"Sign In"</h2>
            {move || error.get().map(|e| view! { <div class="error-msg">{e}</div> })}
            <form on:submit=on_submit>
                <div class="form-group">
                    <label>"Email"</label>
                    <input type="email" required
                        on:input=move |ev| set_email(event_target_value(&ev))
                        prop:value=email />
                </div>
                <div class="form-group">
                    <label>"Password"</label>
                    <input type="password" required
                        on:input=move |ev| set_password(event_target_value(&ev))
                        prop:value=password />
