    background: var(--surface); padding: 1.5rem; border-radius: var(--radius);
    border: 1px solid var(--border); max-width: 500px;
}
.confirm-box { background: #fef2f2; padding: 1rem; border-radius: var(--radius); margin: 1rem 0; }

/* ── Finance ── */
.finance-page { max-width: 900px; margin: 0 auto; }
.expense-review-list { display: flex; flex-direction: column; gap: 1rem; margin-top: 1rem; }
.expense-card {
    background: var(--surface); padding: 1.25rem; border-radius: var(--radius);
    border: 1px solid var(--border);
}
.expense-header { display: flex; justify-content: space-between; margin-bottom: .5rem; }
.expense-meta { display: flex; gap: 1rem; font-size: .85rem; color: var(--text-muted); margin: .75rem 0; flex-wrap: wrap; }
.receipt-badge { background: #dcfce7; color: var(--success); padding: .15rem .5rem; border-radius: 4px; }
.review-actions { display: flex; gap: .75rem; }

/* ── Notifications ── */
.notification-center { background: var(--surface); border-radius: var(--radius); border: 1px solid var(--border); }
.notif-header { display: flex; justify-content: space-between; align-items: center; padding: 1rem 1.25rem; border-bottom: 1px solid var(--border); }
.notif-summary { padding: .5rem 1.25rem; font-size: .85rem; color: var(--text-muted); background: #f8fafc; }
.notif-list { max-height: 400px; overflow-y: auto; }
.notif-item { padding: .75rem 1.25rem; border-bottom: 1px solid var(--border); cursor: pointer; transition: background .1s; }
.notif-item:hover { background: #f8fafc; }
.notif-item.unread { background: #eff6ff; border-left: 3px solid var(--primary); }
.notif-item.read { opacity: .7; }
.notif-title { font-weight: 600; font-size: .9rem; }
.notif-body { font-size: .85rem; color: var(--text-muted); }
.notif-time { font-size: .75rem; color: var(--text-muted); margin-top: .25rem; }

/* ── Empty state ── */
.empty { color: var(--text-muted); font-style: italic; padding: 1rem 0; }

/* ── Favorites ── */
.favorite-list { list-style: none; }
.favorite-list li { padding: .4rem 0; }

/* ── Print styles ── */
@media print {
    .navbar, .action-buttons, .comment-section, .btn { display: none !important; }
    .receipt { border: 2px solid #000; }
}

/* ── Responsive ── */
@media (max-width: 768px) {
    .navbar { flex-direction: column; gap: .75rem; }
    .hero h1 { font-size: 1.75rem; }
    .hero-actions { flex-direction: column; align-items: center; }
    .filters { flex-direction: column; }
    .project-grid { grid-template-columns: 1fr; }
    .stats-grid { grid-template-columns: repeat(2, 1fr); }
}
