1	use leptos::*;
2	use leptos_router::*;
3	
4	use crate::api;
5	use crate::components::receipt::ReceiptDisplay;
6	use crate::state::AuthState;
7	
8	#[component]
9	pub fn DonatePage() -> impl IntoView {
10	    let params = use_params_map();
11	    let auth = use_context::<AuthState>().unwrap();
12	    let project_id = move || params.with(|p| p.get("id").cloned().unwrap_or_default());
13	
14	    let project = create_resource(project_id, |id| async move {
15	        api::get_project(&id).await.ok()
16	    });
17	
18	    let (amount, set_amount) = create_signal(String::new());
19	    let (selected_line, set_selected_line) = create_signal(String::new());
20	    let (donation_result, set_donation_result) = create_signal(Option::<common::DonationRecord>::None);
21	    let (error, set_error) = create_signal(Option::<String>::None);
22	
23	    let on_donate = move |ev: leptos::ev::SubmitEvent| {
24	        ev.prevent_default();
25	        let token = match auth.get_token() {
26	            Some(t) => t,
27	            None => {
28	                set_error(Some("Please sign in to donate".to_string()));
29	                return;
30	            }
31	        };
32	        let pid = project_id();
33	        let amount_str = amount.get();
34	        let cents: i64 = match amount_str.parse::<f64>() {
35	            Ok(v) => (v * 100.0) as i64,
36	            Err(_) => {
37	                set_error(Some("Invalid amount".to_string()));
38	                return;
39	            }
40	        };
41	        let line = selected_line.get();
42	        let budget_line_id = if line.is_empty() { None } else { Some(line) };
43	
44	        spawn_local(async move {
45	            let req = common::DonateRequest {
46	                project_id: pid,
47	                amount_cents: cents,
48	                budget_line_id,
49	            };
50	            match api::donate(&token, &req).await {
51	                Ok(resp) => {
52	                    set_donation_result(Some(resp.donation));
53	                    set_error(None);
54	                }
55	                Err(e) => set_error(Some(e)),
56	            }
57	        });
58	    };
59	
60	    view! {
61	        <div class="donate-page">
62	            <Suspense fallback=move || view! { <p>"Loading..."</p> }>
63	                {move || project.get().map(|data| match data {
64	                    Some(p) => {
65	                        let budget_lines = p.budget_lines.clone();
66	                        view! {
67	                            <h2>{format!("Donate to: {}", p.title)}</h2>
68	                            <div class="project-summary">
69	                                <p>{format!("Goal: ${:.2} | Raised: ${:.2}",
70	                                    p.goal_cents as f64 / 100.0,
71	                                    p.raised_cents as f64 / 100.0)}</p>
72	                            </div>
73	
74	                            {move || {
75	                                if let Some(ref donation) = donation_result.get() {
76	                                    view! {
77	                                        <ReceiptDisplay donation=donation.clone() />
78	                                    }.into_view()
79	                                } else {
80	                                    view! {
81	                                        <form class="donate-form" on:submit=on_donate>
82	                                            {move || error.get().map(|e| view! { <div class="error-msg">{e}</div> })}
83	                                            <div class="form-group">
84	                                                <label>"Donation Amount ($)"</label>
85	                                                <input type="number" step="0.01" min="1" required
86	                                                    placeholder="25.00"
87	                                                    on:input=move |ev| set_amount(event_target_value(&ev))
88	                                                    prop:value=amount />
89	                                            </div>
90	                                            <div class="form-group">
91	                                                <label>"Designate to Budget Line (optional)"</label>
92	                                                <select on:change=move |ev| set_selected_line(event_target_value(&ev))>
93	                                                    <option value="">"General (no designation)"</option>
94	                                                    {budget_lines.clone().into_iter().map(|bl| {
95	                                                        let id = bl.id.clone();
96	                                                        let label = format!("{} (${:.2} allocated)",
97	                                                            bl.name, bl.allocated_cents as f64 / 100.0);
98	                                                        view! {
99	                                                            <option value=id>{label}</option>
100	                                                        }
101	                                                    }).collect::<Vec<_>>()}
102	                                                </select>
103	                                            </div>
104	                                            <button type="submit" class="btn btn-primary btn-lg">
105	                                                "Complete Donation"
106	                                            </button>
107	                                        </form>
108	                                    }.into_view()
109	                                }
110	                            }}
111	                        }.into_view()
112	                    }
113	                    None => view! { <p>"Project not found."</p> }.into_view(),
114	                })}
115	            </Suspense>
116	        </div>
117	    }
118	}
