5	
6	#[component]
7	pub fn DashboardPage() -> impl IntoView {
8	    let auth = use_context::<AuthState>().unwrap();
9	    let (from_date, set_from) = create_signal(String::new());
10	    let (to_date, set_to) = create_signal(String::new());
11	
12	    let stats = create_resource(
13	        move || (auth.get_token(), from_date.get(), to_date.get()),
14	        |(token, from, to)| async move {
15	            match token {
16	                Some(t) => {
17	                    let from_opt = if from.is_empty() { None } else { Some(from) };
18	                    let to_opt = if to.is_empty() { None } else { Some(to) };
19	                    api::dashboard_stats(&t, from_opt.as_deref(), to_opt.as_deref())
20	                        .await
21	                        .ok()
22	                }
23	                None => None,
24	            }
25	        },
26	    );
27	
28	    let on_export = move |_| {
29	        if let Some(token) = auth.get_token() {
30	            let from = from_date.get();
31	            let to = to_date.get();
32	            // Build CSV download URL
33	            let mut parts = vec![];
34	            if !from.is_empty() {
35	                parts.push(format!("from={}", from));
36	            }
37	            if !to.is_empty() {
38	                parts.push(format!("to={}", to));
39	            }
40	            let query = if parts.is_empty() {
41	                String::new()
42	            } else {
43	                format!("?{}", parts.join("&"))
44	            };
45	            // Trigger download by opening in new window
46	            let url = format!("/api/admin/export/csv{}", query);
47	            let _ = web_sys::window().unwrap().open_with_url(&url);
48	        }
49	    };
50	
51	    view! {
52	        <div class="dashboard-page">
53	            <h2>"Operations Dashboard"</h2>
54	
55	            <div class="date-range-filters">
56	                <div class="form-group">
57	                    <label>"From"</label>
58	                    <input type="date" on:input=move |ev| set_from(event_target_value(&ev))
59	                        prop:value=from_date />
60	                </div>
61	                <div class="form-group">
62	                    <label>"To"</label>
63	                    <input type="date" on:input=move |ev| set_to(event_target_value(&ev))
64	                        prop:value=to_date />
65	                </div>
66	                <button class="btn btn-secondary" on:click=on_export>"Export CSV"</button>
67	            </div>
68	
69	            <Suspense fallback=move || view! { <p>"Loading stats..."</p> }>
70	                {move || stats.get().map(|data| match data {
71	                    Some(s) => view! {
72	                        <div class="stats-grid">
73	                            <div class="stat-card">
74	                                <div class="stat-value">
75	                                    {format!("${:.2}", s.gmv_cents as f64 / 100.0)}
76	                                </div>
77	                                <div class="stat-label">"Gross Merchandise Value"</div>
78	                            </div>
79	                            <div class="stat-card">
80	                                <div class="stat-value">{s.total_donations.to_string()}</div>
81	                                <div class="stat-label">"Total Donations"</div>
82	                            </div>
83	                            <div class="stat-card">
84	                                <div class="stat-value">{s.unique_donors.to_string()}</div>
85	                                <div class="stat-label">"Unique Donors"</div>
86	                            </div>
87	                            <div class="stat-card">
88	                                <div class="stat-value">
89	                                    {format!("${:.2}", s.average_donation_cents as f64 / 100.0)}
90	                                </div>
91	                                <div class="stat-label">"Average Donation"</div>
92	                            </div>
93	                            <div class="stat-card">
94	                                <div class="stat-value">
95	                                    {format!("{:.1}%", s.repeat_donor_rate * 100.0)}
96	                                </div>
97	                                <div class="stat-label">"Repeat Donor Rate"</div>
98	                            </div>
99	                            <div class="stat-card">
100	                                <div class="stat-value">
101	                                    {format!("{:.1}%", s.conversion_rate * 100.0)}
102	                                </div>
103	                                <div class="stat-label">"Conversion Rate"</div>
104	                            </div>
105	                        </div>
106	                    }.into_view(),
107	                    None => view! {
108	                        <p class="error-msg">"Unable to load stats. Ensure you have staff access."</p>
109	                    }.into_view(),
110	                })}
111	            </Suspense>
112	        </div>
113	    }
114	}
