1	use leptos::*;
2	
3	use crate::api;
4	use crate::state::AuthState;
5	
6	#[component]
7	pub fn AdminPage() -> impl IntoView {
8	    let auth = use_context::<AuthState>().unwrap();
9	
10	    // Ops log
11	    let (log_page, set_log_page) = create_signal(1i64);
12	    let ops_log = create_resource(
13	        move || (auth.get_token(), log_page.get()),
14	        |(token, page)| async move {
15	            match token {
16	                Some(t) => api::ops_log(&t, page).await.ok(),
17	                None => None,
18	            }
19	        },
20	    );
21	
22	    // Unpublish project
23	    let (unpub_id, set_unpub_id) = create_signal(String::new());
24	    let (unpub_pw, set_unpub_pw) = create_signal(String::new());
25	    let (unpub_msg, set_unpub_msg) = create_signal(Option::<String>::None);
26	    let (confirm_step, set_confirm_step) = create_signal(false);
27	
28	    let do_unpublish = move |_| {
29	        if !confirm_step.get() {
30	            set_confirm_step(true);
31	            return;
32	        }
33	        if let Some(token) = auth.get_token() {
34	            let id = unpub_id.get();
35	            let pw = unpub_pw.get();
36	            spawn_local(async move {
37	                match api::unpublish_project(&token, &id, &pw).await {
38	                    Ok(r) => {
39	                        set_unpub_msg(Some(r.message));
40	                        set_confirm_step(false);
41	                        set_unpub_pw(String::new());
42	                    }
43	                    Err(e) => {
44	                        set_unpub_msg(Some(e));
45	                        set_confirm_step(false);
46	                    }
47	                }
48	            });
49	        }
50	    };
51	
52	    view! {
53	        <div class="admin-page">
54	            <h2>"Administration Panel"</h2>
55	
56	            <section class="admin-section">
57	                <h3>"Sensitive Actions"</h3>
58	
59	                <div class="sensitive-action-card">
60	                    <h4>"Unpublish Project"</h4>
61	                    {move || unpub_msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
62	                    <div class="form-row">
63	                        <input type="text" placeholder="Project ID"
64	                            on:input=move |ev| set_unpub_id(event_target_value(&ev))
65	                            prop:value=unpub_id />
66	                    </div>
67	                    {move || confirm_step.get().then(|| view! {
68	                        <div class="confirm-box">
69	                            <p class="warning">"This is a sensitive action. Please re-enter your password to confirm."</p>
70	                            <input type="password" placeholder="Re-enter password"
71	                                on:input=move |ev| set_unpub_pw(event_target_value(&ev))
72	                                prop:value=unpub_pw />
73	                        </div>
74	                    })}
75	                    <button class="btn btn-danger" on:click=do_unpublish>
76	                        {move || if confirm_step.get() { "Confirm Unpublish" } else { "Unpublish" }}
77	                    </button>
78	                </div>
79	            </section>
80	
81	            <section class="admin-section">
82	                <h3>"Operations Log (Immutable Audit Trail)"</h3>
83	                <Suspense fallback=move || view! { <p>"Loading log..."</p> }>
84	                    {move || ops_log.get().map(|data| match data {
85	                        Some(entries) => view! {
86	                            <table class="data-table">
87	                                <thead>
88	                                    <tr>
89	                                        <th>"Time"</th>
90	                                        <th>"Actor"</th>
91	                                        <th>"Action"</th>
92	                                        <th>"Detail"</th>
93	                                    </tr>
94	                                </thead>
95	                                <tbody>
96	                                    {entries.into_iter().map(|e| view! {
97	                                        <tr>
98	                                            <td>{&e.created_at}</td>
99	                                            <td>{&e.actor_name}</td>
100	                                            <td><span class="badge">{&e.action}</span></td>
101	                                            <td>{&e.detail}</td>
102	                                        </tr>
103	                                    }).collect::<Vec<_>>()}
104	                                </tbody>
105	                            </table>
106	                            <div class="pagination">
107	                                <button class="btn btn-sm"
108	                                    disabled=move || log_page.get() <= 1
109	                                    on:click=move |_| set_log_page.update(|p| *p -= 1)>
110	                                    "Previous"
111	                                </button>
112	                                <span class="page-info">{move || format!("Page {}", log_page.get())}</span>
113	                                <button class="btn btn-sm"
114	                                    on:click=move |_| set_log_page.update(|p| *p += 1)>
115	                                    "Next"
116	                                </button>
117	                            </div>
118	                        }.into_view(),
