1	use leptos::*;
2	
3	use crate::api;
4	use crate::state::AuthState;
5	
6	#[component]
7	pub fn FinancePage() -> impl IntoView {
8	    let auth = use_context::<AuthState>().unwrap();
9	    let (refresh_counter, set_refresh) = create_signal(0u32);
10	
11	    let expenses = create_resource(
12	        move || (auth.get_token(), refresh_counter.get()),
13	        |(token, _)| async move {
14	            match token {
15	                Some(t) => api::pending_expenses(&t).await.ok(),
16	                None => None,
17	            }
18	        },
19	    );
20	
21	    let (review_note, set_review_note) = create_signal(String::new());
22	    let (review_msg, set_review_msg) = create_signal(Option::<String>::None);
23	
24	    let do_review = move |expense_id: String, approved: bool| {
25	        if let Some(token) = auth.get_token() {
26	            let note = review_note.get();
27	            let note_opt = if note.is_empty() { None } else { Some(note) };
28	            spawn_local(async move {
29	                match api::review_expense(&token, &expense_id, approved, note_opt.as_deref()).await {
30	                    Ok(r) => {
31	                        set_review_msg(Some(r.message));
32	                        set_refresh.update(|c| *c += 1);
33	                    }
34	                    Err(e) => set_review_msg(Some(e)),
35	                }
36	            });
37	        }
38	    };
39	
40	    view! {
41	        <div class="finance-page">
42	            <h2>"Finance Review"</h2>
43	            <p>"Verify receipts and approve or reject expense disclosures."</p>
44	
45	            {move || review_msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
46	
47	            <div class="form-group">
48	                <label>"Review Note (optional)"</label>
49	                <textarea placeholder="Add a note for the review..."
50	                    on:input=move |ev| set_review_note(event_target_value(&ev))
51	                    prop:value=review_note />
52	            </div>
53	
54	            <Suspense fallback=move || view! { <p>"Loading pending expenses..."</p> }>
55	                {move || expenses.get().map(|data| match data {
56	                    Some(list) if !list.is_empty() => {
57	                        view! {
58	                            <div class="expense-review-list">
59	                                {list.into_iter().map(|exp| {
60	                                    let eid_approve = exp.id.clone();
61	                                    let eid_reject = exp.id.clone();
62	                                    view! {
63	                                        <div class="expense-card">
64	                                            <div class="expense-header">
65	                                                <strong>{&exp.budget_line_name}</strong>
66	                                                <span class="amount">
67	                                                    {format!("${:.2}", exp.amount_cents as f64 / 100.0)}
68	                                                </span>
69	                                            </div>
70	                                            <p>{&exp.description}</p>
71	                                            <div class="expense-meta">
72	                                                <span>"Project: " {&exp.project_id}</span>
73	                                                <span>"Date: " {&exp.created_at}</span>
74	                                                {exp.receipt_url.as_ref().map(|_| view! {
75	                                                    <span class="receipt-badge">"Has Receipt"</span>
76	                                                })}
77	                                            </div>
78	                                            <div class="review-actions">
79	                                                <button class="btn btn-success"
80	                                                    on:click={
81	                                                        let do_review = do_review.clone();
82	                                                        move |_| do_review(eid_approve.clone(), true)
83	                                                    }>
84	                                                    "Approve"
85	                                                </button>
86	                                                <button class="btn btn-danger"
87	                                                    on:click={
88	                                                        let do_review = do_review.clone();
89	                                                        move |_| do_review(eid_reject.clone(), false)
90	                                                    }>
91	                                                    "Reject"
92	                                                </button>
93	                                            </div>
94	                                        </div>
95	                                    }
96	                                }).collect::<Vec<_>>()}
97	                            </div>
98	                        }.into_view()
99	                    }
100	                    Some(_) => view! {
101	                        <p class="empty">"No pending expenses to review."</p>
102	                    }.into_view(),
103	                    None => view! {
104	                        <p class="error-msg">"Unable to load. Finance reviewer access required."</p>
105	                    }.into_view(),
106	                })}
107	            </Suspense>
108	        </div>
109	    }
110	}
