5	
6	#[component]
7	pub fn CommentSection(project_id: String) -> impl IntoView {
8	    let auth = use_context::<AuthState>().unwrap();
9	    let (refresh, set_refresh) = create_signal(0u32);
10	    let pid = project_id.clone();
11	
12	    let comments = create_resource(
13	        move || (pid.clone(), refresh.get()),
14	        |(pid, _)| async move { api::list_comments(&pid).await.ok() },
15	    );
16	
17	    let (new_comment, set_new_comment) = create_signal(String::new());
18	    let (ticket_subject, set_ticket_subject) = create_signal(String::new());
19	    let (ticket_body, set_ticket_body) = create_signal(String::new());
20	    let (feedback_msg, set_feedback_msg) = create_signal(Option::<String>::None);
21	
22	    let pid_for_comment = project_id.clone();
23	    let on_post_comment = move |ev: leptos::ev::SubmitEvent| {
24	        ev.prevent_default();
25	        if let Some(token) = auth.get_token() {
26	            let pid = pid_for_comment.clone();
27	            let body = new_comment.get();
28	            spawn_local(async move {
29	                match api::post_comment(&token, &pid, &body).await {
30	                    Ok(_) => {
31	                        set_new_comment(String::new());
32	                        set_refresh.update(|c| *c += 1);
33	                    }
34	                    Err(e) => set_feedback_msg(Some(e)),
35	                }
36	            });
37	        }
38	    };
39	
40	    let pid_for_ticket = project_id.clone();
41	    let on_submit_ticket = move |ev: leptos::ev::SubmitEvent| {
42	        ev.prevent_default();
43	        if let Some(token) = auth.get_token() {
44	            let pid = pid_for_ticket.clone();
45	            let subject = ticket_subject.get();
46	            let body = ticket_body.get();
47	            spawn_local(async move {
48	                match api::submit_ticket(&token, &pid, &subject, &body).await {
49	                    Ok(r) => {
50	                        set_feedback_msg(Some(r.message));
51	                        set_ticket_subject(String::new());
52	                        set_ticket_body(String::new());
53	                    }
54	                    Err(e) => set_feedback_msg(Some(e)),
55	                }
56	            });
57	        }
58	    };
59	
60	    view! {
61	        <div class="comment-section">
62	            <h3>"Comments"</h3>
63	            {move || feedback_msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
64	
65	            <Suspense fallback=move || view! { <p>"Loading comments..."</p> }>
66	                {move || comments.get().map(|data| match data {
67	                    Some(list) if !list.is_empty() => {
68	                        view! {
69	                            <div class="comment-list">
70	                                {list.into_iter().map(|c| {
71	                                    let cid = c.id.clone();
72	                                    let is_admin = auth.user.get().map_or(false, |u|
73	                                        matches!(u.role, common::Role::Administrator));
74	                                    let on_delete = move |_| {
75	                                        let cid = cid.clone();
76	                                        if let Some(token) = auth.get_token() {
77	                                            spawn_local(async move {
78	                                                let _ = api::delete_comment(&token, &cid).await;
79	                                                set_refresh.update(|c| *c += 1);
80	                                            });
81	                                        }
82	                                    };
83	                                    view! {
84	                                        <div class="comment">
85	                                            <div class="comment-header">
86	                                                <strong>{&c.author_name}</strong>
87	                                                <span class="comment-date">{&c.created_at}</span>
88	                                                {is_admin.then(|| view! {
89	                                                    <button class="btn-delete-sm" on:click=on_delete>
90	                                                        "Remove"
91	                                                    </button>
92	                                                })}
93	                                            </div>
94	                                            <p>{&c.body}</p>
95	                                        </div>
96	                                    }
97	                                }).collect::<Vec<_>>()}
98	                            </div>
99	                        }.into_view()
100	                    }
101	                    _ => view! { <p class="empty">"No comments yet. Be the first!"</p> }.into_view(),
102	                })}
103	            </Suspense>
104	
105	            {move || auth.is_logged_in().then(|| view! {
106	                <form class="comment-form" on:submit=on_post_comment>
107	                    <textarea placeholder="Write a comment..."
108	                        on:input=move |ev| set_new_comment(event_target_value(&ev))
109	                        prop:value=new_comment />
110	                    <button type="submit" class="btn btn-primary btn-sm">"Post Comment"</button>
111	                </form>
112	            })}
113	
114	            <h3>"Submit Feedback"</h3>
115	            {move || auth.is_logged_in().then(|| view! {
116	                <form class="ticket-form" on:submit=on_submit_ticket>
117	                    <div class="form-group">
118	                        <input type="text" placeholder="Subject"
119	                            on:input=move |ev| set_ticket_subject(event_target_value(&ev))
120	                            prop:value=ticket_subject />
121	                    </div>
122	                    <div class="form-group">
123	                        <textarea placeholder="Describe your feedback..."
124	                            on:input=move |ev| set_ticket_body(event_target_value(&ev))
125	                            prop:value=ticket_body />
126	                    </div>
127	                    <button type="submit" class="btn btn-secondary btn-sm">"Submit Feedback"</button>
128	                </form>
129	            })}
130	        </div>
131	    }
132	}
