pub fn get_donation(db: &DbPool, donation_id: &str) -> Option<common::DonationRecord> {
    let conn = db.lock();
    conn.query_row(
        "SELECT d.id, d.pledge_number, d.project_id, p.title, d.donor_id, d.amount_cents, \
         d.budget_line_id, bl.name, d.created_at \
         FROM donations d \
         JOIN projects p ON d.project_id = p.id \
         LEFT JOIN budget_lines bl ON d.budget_line_id = bl.id \
         WHERE d.id = ?1",
        params![donation_id],
        |row| {
            Ok(common::DonationRecord {
                id: row.get(0)?,
                pledge_number: row.get(1)?,
                project_id: row.get(2)?,
                project_title: row.get(3)?,
                donor_id: row.get(4)?,
                amount_cents: row.get(5)?,
                budget_line_id: row.get(6)?,
                budget_line_name: row.get(7)?,
                created_at: row.get(8)?,
            })
        },
    )
    .ok()
}

pub fn list_user_donations(db: &DbPool, user_id: &str) -> Vec<common::DonationRecord> {
    let conn = db.lock();
    let mut stmt = conn
        .prepare(
            "SELECT d.id, d.pledge_number, d.project_id, p.title, d.donor_id, d.amount_cents, \
             d.budget_line_id, bl.name, d.created_at \
             FROM donations d \
             JOIN projects p ON d.project_id = p.id \
             LEFT JOIN budget_lines bl ON d.budget_line_id = bl.id \
             WHERE d.donor_id = ?1 ORDER BY d.created_at DESC"
        )
        .unwrap();
    stmt.query_map(params![user_id], |row| {
        Ok(common::DonationRecord {
            id: row.get(0)?,
            pledge_number: row.get(1)?,
            project_id: row.get(2)?,
            project_title: row.get(3)?,
            donor_id: row.get(4)?,
            amount_cents: row.get(5)?,
