117	fn load_or_create_secret(path: &str) -> Vec<u8> {
118	    use std::path::Path;
119	    let p = Path::new(path);
120	    if p.exists() {
121	        std::fs::read(p).expect("Failed to read HMAC key")
122	    } else {
123	        use rand::Rng;
124	        let secret: Vec<u8> = (0..64).map(|_| rand::thread_rng().gen()).collect();
125	        if let Some(parent) = p.parent() {
126	            std::fs::create_dir_all(parent).ok();
127	        }
128	        std::fs::write(p, &secret).expect("Failed to write HMAC key");
129	        secret
130	    }
131	}
