                    <table class="data-table">
                        <thead><tr><th>"Kind"</th><th>"Count"</th></tr></thead>
                        <tbody>
                            {m.events_by_kind.into_iter().map(|(kind, count)| view! {
                                <tr><td>{kind}</td><td>{count.to_string()}</td></tr>
                            }).collect::<Vec<_>>()}
                        </tbody>
                    </table>
