95	/// Request a refund (creates a negative reversal record pending Finance Reviewer approval).
96	pub async fn request_refund(
97	    State(state): State<Arc<AppState>>,
98	    request: axum::http::Request<axum::body::Body>,
99	) -> Result<Json<DonateResponse>, (StatusCode, Json<ApiError>)> {
100	    let auth = require_auth(request.extensions())
101	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
102	
103	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
104	        .await
105	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
106	    let req: RefundRequest = serde_json::from_slice(&body)
107	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
108	
109	    // Get original donation
110	    let original = db::get_donation(&state.db, &req.donation_id).ok_or_else(|| {
111	        (StatusCode::NOT_FOUND, Json(ApiError { error: "Original donation not found".into() }))
112	    })?;
113	
114	    // Only the original donor may request a refund
115	    if original.donor_id != auth.user_id {
116	        return Err((StatusCode::FORBIDDEN, Json(ApiError {
117	            error: "Only the original donor can request a refund for this donation".into(),
118	        })));
119	    }
120	
121	    let reversal_id = uuid::Uuid::new_v4().to_string();
122	    let pledge_number = format!("REF-{}", &reversal_id[..8].to_uppercase());
123	
124	    db::create_donation(
125	        &state.db,
126	        &reversal_id,
127	        &pledge_number,
128	        &original.project_id,
129	        &original.donor_id,
130	        -original.amount_cents, // Negative amount
131	        &original.payment_method,
132	        true,
133	        Some(&req.donation_id),
134	        original.budget_line_id.as_deref(),
135	    )
136	    .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
137	
138	    let reversal = db::get_donation(&state.db, &reversal_id).unwrap();
139	
140	    db::append_ops_log(
141	        &state.db,
142	        &auth.user_id,
143	        "user",
144	        "request_refund",
145	        &format!("Requested refund for donation {} (reason: {})", req.donation_id, req.reason),
146	    );
147	
148	    Ok(Json(DonateResponse { donation: reversal }))
149	}
