151	/// Approve or reject a pending refund (Finance Reviewer only, requires password).
152	pub async fn approve_refund(
153	    State(state): State<Arc<AppState>>,
154	    request: axum::http::Request<axum::body::Body>,
155	) -> Result<Json<ApiSuccess>, (StatusCode, Json<ApiError>)> {
156	    let auth = require_auth(request.extensions())
157	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
158	    let user = require_role(&state.db, &auth.user_id, &[Role::FinanceReviewer, Role::Administrator])
159	        .map_err(|s| (s, Json(ApiError { error: "Forbidden".into() })))?;
160	
161	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
162	        .await
163	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
164	    let req: ApproveRefundRequest = serde_json::from_slice(&body)
165	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
166	
167	    // Verify password (sensitive action)
168	    let hash = db::get_user_password_hash(&state.db, &auth.user_id)
169	        .ok_or_else(|| (StatusCode::UNAUTHORIZED, Json(ApiError { error: "User not found".into() })))?;
170	    if !crate::auth::verify_password(&req.password, &hash) {
171	        return Err((StatusCode::UNAUTHORIZED, Json(ApiError { error: "Invalid password".into() })));
172	    }
173	
174	    db::approve_reversal(&state.db, &req.donation_id, req.approved)
175	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
176	
177	    let action = if req.approved { "approved" } else { "rejected" };
178	    db::append_ops_log(&state.db, &auth.user_id, &user.display_name, "approve_refund",
179	        &format!("Refund {} {}", req.donation_id, action));
180	
181	    Ok(Json(ApiSuccess { message: format!("Refund {}", action) }))
182	}
