1059	        stmt.query_row(refs.as_slice(), |row| row.get(0)).unwrap_or(0)
1060	    };
1061	
1062	    let total_sql = format!(
1063	        "SELECT COUNT(*) FROM donations d WHERE d.is_reversal = 0 {}", date_clause
