1106	/// Build a parameterized date clause with ?-placeholders for from/to.
1107	/// Returns (clause_string, params_vec). Placeholder numbering starts at 1.
1108	fn build_date_params(from: Option<&str>, to: Option<&str>) -> (String, Vec<Box<dyn rusqlite::types::ToSql>>) {
1109	    let mut clauses = Vec::new();
1110	    let mut params: Vec<Box<dyn rusqlite::types::ToSql>> = Vec::new();
1111	    if let Some(f) = from {
1112	        params.push(Box::new(f.to_string()));
1113	        clauses.push(format!("AND d.created_at >= ?{}", params.len()));
1114	    }
1115	    if let Some(t) = to {
1116	        params.push(Box::new(t.to_string()));
1117	        clauses.push(format!("AND d.created_at <= ?{}", params.len()));
1118	    }
1119	    (clauses.join(" "), params)
1120	}
