403	pub fn list_projects(db: &DbPool, filter: &common::ProjectFilter, limit: i64, offset: i64) -> (Vec<common::ProjectSummary>, i64) {
404	    let conn = db.lock();
405	    let mut where_clauses = vec!["1=1".to_string()];
406	    let mut param_values: Vec<Box<dyn rusqlite::types::ToSql>> = Vec::new();
407	
408	    if let Some(ref cause) = filter.cause {
409	        param_values.push(Box::new(cause.clone()));
410	        where_clauses.push(format!("p.cause = ?{}", param_values.len()));
411	    }
412	    if let Some(ref status) = filter.status {
413	        param_values.push(Box::new(status.clone()));
414	        where_clauses.push(format!("p.status = ?{}", param_values.len()));
415	    }
416	    if let Some(ref zip) = filter.zip_code {
417	        param_values.push(Box::new(zip.clone()));
418	        where_clauses.push(format!("p.zip_code = ?{}", param_values.len()));
419	    }
420	    if let Some(ref search) = filter.search {
421	        param_values.push(Box::new(format!("%{}%", search)));
422	        where_clauses.push(format!("(p.title LIKE ?{} OR p.description LIKE ?{})", param_values.len(), param_values.len()));
423	    }
424	
425	    let where_sql = where_clauses.join(" AND ");
426	
427	    let count_sql = format!(
428	        "SELECT COUNT(*) FROM projects p WHERE {}",
429	        where_sql
430	    );
431	    let total: i64 = {
432	        let mut stmt = conn.prepare(&count_sql).unwrap();
433	        let param_refs: Vec<&dyn rusqlite::types::ToSql> = param_values.iter().map(|p| p.as_ref()).collect();
434	        stmt.query_row(param_refs.as_slice(), |row| row.get(0)).unwrap_or(0)
435	    };
436	
437	    let query_sql = format!(
438	        "SELECT p.id, p.title, p.cause, p.zip_code, p.status, p.goal_cents, \
439	         COALESCE((SELECT SUM(d.amount_cents) FROM donations d WHERE d.project_id = p.id AND (d.is_reversal = 0 OR d.reversal_approved = 1)), 0), \
440	         COALESCE((SELECT SUM(e.amount_cents) FROM expenses e WHERE e.project_id = p.id AND e.disclosure_status = 'approved'), 0), \
441	         u.display_name, p.created_at \
442	         FROM projects p JOIN users u ON p.manager_id = u.id \
443	         WHERE {} ORDER BY p.created_at DESC LIMIT ?{} OFFSET ?{}",
444	        where_sql,
445	        param_values.len() + 1,
446	        param_values.len() + 2
447	    );
448	    param_values.push(Box::new(limit));
449	    param_values.push(Box::new(offset));
