48	/// Rate-limiting middleware: 60 requests per minute per session token.
49	pub async fn rate_limit_middleware(
50	    State(state): State<Arc<AppState>>,
51	    headers: HeaderMap,
52	    request: Request,
53	    next: Next,
54	) -> Result<Response, StatusCode> {
55	    let key = headers
56	        .get("authorization")
57	        .and_then(|v| v.to_str().ok())
58	        .unwrap_or("anonymous")
59	        .to_string();
60	
61	    if !state.rate_limiter.check(&key) {
62	        return Err(StatusCode::TOO_MANY_REQUESTS);
63	    }
64	
65	    Ok(next.run(request).await)
66	}
