68	/// Authentication extraction: reads Authorization header, validates token, injects user_id.
69	pub async fn auth_middleware(
70	    State(state): State<Arc<AppState>>,
71	    mut request: Request,
72	    next: Next,
73	) -> Result<Response, StatusCode> {
74	    let auth_header = request
75	        .headers()
76	        .get("authorization")
77	        .and_then(|v| v.to_str().ok())
78	        .map(|s| s.trim_start_matches("Bearer ").to_string());
79	
80	    if let Some(token) = auth_header {
81	        if let Some(user_id) = validate_session_token(&token, &state.hmac_secret) {
82	            request.extensions_mut().insert(AuthUser { user_id });
83	        }
84	    }
85	
86	    Ok(next.run(request).await)
87	}
