89	/// Nonce replay protection middleware.
90	pub async fn nonce_middleware(
91	    State(state): State<Arc<AppState>>,
92	    headers: HeaderMap,
93	    request: Request,
94	    next: Next,
95	) -> Result<Response, StatusCode> {
96	    // Only enforce nonce on mutating requests
97	    let method = request.method().clone();
98	    if method == axum::http::Method::GET || method == axum::http::Method::OPTIONS {
99	        return Ok(next.run(request).await);
100	    }
101	
102	    let nonce = headers.get("x-nonce").and_then(|v| v.to_str().ok());
103	    match nonce {
104	        Some(n) => {
105	            if !crate::db::consume_nonce(&state.db, n).unwrap_or(false) {
106	                return Err(StatusCode::CONFLICT); // Nonce already used or expired
107	            }
108	        }
109	        None => {
110	            // Nonce is mandatory for all mutating requests
111	            return Err(StatusCode::BAD_REQUEST);
112	        }
113	    }
114	
115	    Ok(next.run(request).await)
116	}
