188	/// Download the tamper-evident service proof for a completed fulfillment.
189	pub async fn service_proof(
190	    State(state): State<Arc<AppState>>,
191	    Path(fulfillment_id): Path<String>,
192	) -> Result<Json<ServiceProof>, (StatusCode, Json<ApiError>)> {
193	    let f = db::get_fulfillment(&state.db, &fulfillment_id)
194	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Fulfillment not found".into() })))?;
195	
196	    if !f.is_complete {
197	        return Err((StatusCode::BAD_REQUEST, Json(ApiError { error: "Fulfillment not yet complete".into() })));
198	    }
199	
200	    let project = db::get_project_detail(&state.db, &f.project_id)
201	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Project not found".into() })))?;
202	
203	    Ok(Json(ServiceProof {
204	        fulfillment_id: f.id,
205	        project_id: f.project_id,
206	        project_title: project.title,
207	        arrival_at: f.arrival_at.unwrap_or_default(),
208	        start_at: f.start_at.unwrap_or_default(),
209	        end_at: f.end_at.unwrap_or_default(),
210	        service_record_hash: f.service_record_hash.unwrap_or_default(),
211	        generated_at: chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
212	    }))
213	}
