754	pub fn review_expense(db: &DbPool, expense_id: &str, approved: bool, reviewer_id: &str, note: Option<&str>, encryption_key: &[u8; 32]) -> SqlResult<usize> {
755	    let conn = db.lock();
756	    let status = if approved { "approved" } else { "rejected" };
757	    // Encrypt reviewer_note at rest
758	    let encrypted_note: Option<String> = note.and_then(|n| {
759	        if n.is_empty() { None } else { crate::crypto::encrypt(n, encryption_key).ok() }
760	    });
761	    conn.execute(
762	        "UPDATE expenses SET disclosure_status = ?1, reviewer_id = ?2, reviewer_note = ?3 WHERE id = ?4",
763	        params![status, reviewer_id, encrypted_note, expense_id],
764	    )
765	}
766	
767	/// Decrypt a reviewer_note value that was encrypted at rest.
768	fn decrypt_reviewer_note(encrypted: Option<String>, key: &[u8; 32]) -> Option<String> {
769	    encrypted.and_then(|enc| {
770	        if enc.is_empty() { return None; }
771	        crate::crypto::decrypt(&enc, key).ok()
772	    })
773	}
