7	pub fn CommentSection(project_id: String) -> impl IntoView {
8	    let auth = use_context::<AuthState>().unwrap();
9	    let (refresh, set_refresh) = create_signal(0u32);
10	    let pid = project_id.clone();
11	
12	    let comments = create_resource(
13	        move || (pid.clone(), refresh.get()),
14	        |(pid, _)| async move { api::list_comments(&pid).await.ok() },
15	    );
16	
17	    let (pending_delete, set_pending_delete) = create_signal(Option::<String>::None);
18	    let (new_comment, set_new_comment) = create_signal(String::new());
19	    let (ticket_subject, set_ticket_subject) = create_signal(String::new());
20	    let (ticket_body, set_ticket_body) = create_signal(String::new());
21	    let (feedback_msg, set_feedback_msg) = create_signal(Option::<String>::None);
22	
23	    let pid_for_comment = std::rc::Rc::new(project_id.clone());
24	    let on_post_comment = {
25	        let pid = pid_for_comment.clone();
26	        move |ev: leptos::ev::SubmitEvent| {
27	            ev.prevent_default();
28	            if let Some(token) = auth.get_token() {
29	                let pid = (*pid).clone();
30	                let body = new_comment.get();
31	                spawn_local(async move {
32	                    match api::post_comment(&token, &pid, &body).await {
33	                        Ok(_) => {
34	                            set_new_comment.set(String::new());
35	                            set_refresh.update(|c| *c += 1);
36	                        }
37	                        Err(e) => set_feedback_msg.set(Some(e)),
38	                    }
39	                });
40	            }
41	        }
42	    };
43	
44	    let pid_for_ticket = std::rc::Rc::new(project_id.clone());
45	    let on_submit_ticket = {
46	        let pid = pid_for_ticket.clone();
47	        move |ev: leptos::ev::SubmitEvent| {
48	            ev.prevent_default();
49	            if let Some(token) = auth.get_token() {
50	                let pid = (*pid).clone();
51	                let subject = ticket_subject.get();
52	                let body = ticket_body.get();
53	                spawn_local(async move {
54	                    match api::submit_ticket(&token, &pid, &subject, &body).await {
55	                        Ok(r) => {
56	                            set_feedback_msg.set(Some(r.message));
57	                            set_ticket_subject.set(String::new());
58	                            set_ticket_body.set(String::new());
59	                        }
60	                        Err(e) => set_feedback_msg.set(Some(e)),
61	                    }
62	                });
63	            }
64	        }
65	    };
66	
67	    view! {
68	        <div class="comment-section">
69	            <h3>"Comments"</h3>
70	            {move || feedback_msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
71	
72	            <Suspense fallback=move || view! { <p>"Loading comments..."</p> }>
73	                {move || comments.get().map(|data| match data {
74	                    Some(list) if !list.is_empty() => {
75	                        view! {
76	                            <div class="comment-list">
77	                                {list.into_iter().map(|c| {
78	                                    let cid = c.id.clone();
79	                                    let cid2 = c.id.clone();
80	                                    let is_admin = auth.user.get().map_or(false, |u|
81	                                        matches!(u.role, common::Role::Administrator));
82	                                    // Two-step: first click sets pending, second confirms
83	                                    let on_delete_click = move |_| {
84	                                        let current_pending = pending_delete.get();
85	                                        if current_pending.as_deref() == Some(&cid) {
86	                                            // Second click: confirm deletion
87	                                            let cid = cid.clone();
88	                                            if let Some(token) = auth.get_token() {
89	                                                spawn_local(async move {
90	                                                    let _ = api::delete_comment(&token, &cid).await;
91	                                                    set_refresh.update(|c| *c += 1);
92	                                                    set_pending_delete.set(None);
93	                                                });
94	                                            }
95	                                        } else {
96	                                            // First click: arm confirmation
97	                                            set_pending_delete.set(Some(cid.clone()));
98	                                        }
99	                                    };
100	                                    view! {
101	                                        <div class="comment">
102	                                            <div class="comment-header">
103	                                                <strong>{&c.author_name}</strong>
104	                                                <span class="comment-date">{&c.created_at}</span>
105	                                                {is_admin.then(move || {
106	                                                    let is_armed = move || pending_delete.get().as_deref() == Some(cid2.as_str());
107	                                                    view! {
108	                                                        <button class="btn-delete-sm" on:click=on_delete_click>
109	                                                            {move || if is_armed() { "Confirm Remove?" } else { "Remove" }}
110	                                                        </button>
111	                                                    }
112	                                                })}
113	                                            </div>
114	                                            <p>{&c.body}</p>
115	                                        </div>
116	                                    }
117	                                }).collect::<Vec<_>>()}
118	                            </div>
119	                        }.into_view()
120	                    }
121	                    _ => view! { <p class="empty">"No comments yet. Be the first!"</p> }.into_view(),
122	                })}
123	            </Suspense>
124	
125	            {move || {
126	                let on_post_comment = on_post_comment.clone();
127	                auth.is_logged_in().then(move || view! {
128	                    <form class="comment-form" on:submit=on_post_comment>
