132	                        <button type="submit" class="btn btn-primary btn-sm">"Post Comment"</button>
133	                    </form>
134	                })
135	            }}
136	
137	            <h3>"Submit Feedback"</h3>
138	            {move || {
139	                let on_submit_ticket = on_submit_ticket.clone();
140	                auth.is_logged_in().then(move || view! {
141	                    <form class="ticket-form" on:submit=on_submit_ticket>
142	                    <div class="form-group">
143	                        <input type="text" placeholder="Subject"
144	                            on:input=move |ev| set_ticket_subject.set(event_target_value(&ev))
145	                            prop:value=ticket_subject />
146	                    </div>
147	                    <div class="form-group">
148	                        <textarea placeholder="Describe your feedback..."
149	                            on:input=move |ev| set_ticket_body.set(event_target_value(&ev))
150	                            prop:value=ticket_body />
151	                    </div>
152	                    <button type="submit" class="btn btn-secondary btn-sm">"Submit Feedback"</button>
153	                </form>
154	                })
155	            }}
156	        </div>
157	    }
158	}
