1	use gloo_net::http::Request;
2	use serde::{de::DeserializeOwned, Serialize};
3	
4	const BASE: &str = "/api";
5	
6	/// Fetch a fresh nonce from the server (required for every mutating request).
7	async fn fetch_nonce() -> Result<String, String> {
8	    let resp = Request::get(&format!("{}/auth/nonce", BASE))
9	        .send()
10	        .await
11	        .map_err(|e| e.to_string())?;
12	    let val: serde_json::Value = resp.json().await.map_err(|e| e.to_string())?;
13	    val["nonce"]
14	        .as_str()
15	        .map(|s| s.to_string())
16	        .ok_or_else(|| "Failed to obtain nonce".into())
17	}
18	
19	async fn get_json<T: DeserializeOwned>(path: &str, token: Option<&str>) -> Result<T, String> {
20	    let mut req = Request::get(&format!("{}{}", BASE, path));
21	    if let Some(t) = token {
22	        req = req.header("Authorization", &format!("Bearer {}", t));
23	    }
24	    let resp = req.send().await.map_err(|e| e.to_string())?;
25	    if !resp.ok() {
26	        let text = resp.text().await.unwrap_or_default();
27	        return Err(text);
28	    }
29	    resp.json().await.map_err(|e| e.to_string())
30	}
31	
32	async fn post_json<T: DeserializeOwned, B: Serialize>(
33	    path: &str,
34	    body: &B,
35	    token: Option<&str>,
36	) -> Result<T, String> {
37	    let nonce = fetch_nonce().await?;
38	    let mut req = Request::post(&format!("{}{}", BASE, path))
39	        .header("X-Nonce", &nonce);
40	    if let Some(t) = token {
41	        req = req.header("Authorization", &format!("Bearer {}", t));
42	    }
43	    let resp = req
44	        .json(body)
45	        .map_err(|e| e.to_string())?
46	        .send()
47	        .await
48	        .map_err(|e| e.to_string())?;
49	    if !resp.ok() {
50	        let text = resp.text().await.unwrap_or_default();
51	        return Err(text);
52	    }
53	    resp.json().await.map_err(|e| e.to_string())
54	}
55	
56	async fn put_json<T: DeserializeOwned, B: Serialize>(
57	    path: &str,
58	    body: &B,
59	    token: Option<&str>,
60	) -> Result<T, String> {
61	    let nonce = fetch_nonce().await?;
62	    let mut req = Request::put(&format!("{}{}", BASE, path))
63	        .header("X-Nonce", &nonce);
64	    if let Some(t) = token {
65	        req = req.header("Authorization", &format!("Bearer {}", t));
66	    }
67	    let resp = req
68	        .json(body)
69	        .map_err(|e| e.to_string())?
70	        .send()
71	        .await
72	        .map_err(|e| e.to_string())?;
73	    if !resp.ok() {
74	        let text = resp.text().await.unwrap_or_default();
75	        return Err(text);
76	    }
77	    resp.json().await.map_err(|e| e.to_string())
78	}
