97	/// Record a checkpoint by validating the OTP code and applying time-consistency rules.
98	pub async fn record_checkpoint(
99	    State(state): State<Arc<AppState>>,
100	    request: axum::http::Request<axum::body::Body>,
101	) -> Result<Json<ApiSuccess>, (StatusCode, Json<ApiError>)> {
102	    let auth = require_auth(request.extensions())
103	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
104	
105	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
106	        .await
107	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
108	    let req: RecordCheckpointRequest = serde_json::from_slice(&body)
109	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
110	
111	    // Validate code
112	    let valid = db::consume_checkpoint_code(&state.db, &req.fulfillment_id, req.checkpoint.as_str(), &req.code)
113	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
114	
115	    if !valid {
116	        return Err((StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid or expired code".into() })));
117	    }
118	
119	    let fulfillment = db::get_fulfillment(&state.db, &req.fulfillment_id)
120	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Fulfillment not found".into() })))?;
121	
122	    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
123	
124	    // Time-consistency rules
125	    match req.checkpoint {
126	        CheckpointKind::Arrival => {
127	            // Arrival can happen anytime
128	        }
129	        CheckpointKind::Start => {
130	            // Start must be within 2 hours of arrival
131	            if let Some(ref arrival) = fulfillment.arrival_at {
132	                if let Ok(arrival_time) = chrono::NaiveDateTime::parse_from_str(arrival, "%Y-%m-%d %H:%M:%S") {
133	                    if let Ok(now_time) = chrono::NaiveDateTime::parse_from_str(&now, "%Y-%m-%d %H:%M:%S") {
134	                        let diff = now_time.signed_duration_since(arrival_time);
135	                        if diff.num_hours() > 2 {
136	                            return Err((StatusCode::BAD_REQUEST, Json(ApiError {
137	                                error: "Start must be within 2 hours of arrival".into()
138	                            })));
139	                        }
140	                    }
141	                }
142	            } else {
143	                return Err((StatusCode::BAD_REQUEST, Json(ApiError {
144	                    error: "Arrival must be recorded before start".into()
145	                })));
146	            }
147	        }
148	        CheckpointKind::End => {
149	            // End must be after start
150	            if fulfillment.start_at.is_none() {
151	                return Err((StatusCode::BAD_REQUEST, Json(ApiError {
152	                    error: "Start must be recorded before end".into()
153	                })));
154	            }
155	        }
156	    }
157	
158	    db::record_checkpoint(&state.db, &req.fulfillment_id, req.checkpoint.as_str(), &now)
159	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
160	
161	    // If end was recorded, check if we can mark complete and generate service record
162	    if req.checkpoint == CheckpointKind::End {
163	        let updated = db::get_fulfillment(&state.db, &req.fulfillment_id).unwrap();
164	        if updated.arrival_at.is_some() && updated.start_at.is_some() && updated.end_at.is_some() {
165	            // Generate tamper-evident hash
166	            let record_data = format!(
167	                "{}|{}|{}|{}|{}",
168	                updated.id,
169	                updated.project_id,
170	                updated.arrival_at.as_deref().unwrap_or(""),
171	                updated.start_at.as_deref().unwrap_or(""),
172	                updated.end_at.as_deref().unwrap_or(""),
173	            );
174	            let mut hasher = Sha256::new();
175	            hasher.update(record_data.as_bytes());
176	            let hash = hex::encode(hasher.finalize());
177	
178	            let _ = db::complete_fulfillment(&state.db, &req.fulfillment_id, &hash);
179	        }
180	    }
181	
182	    db::append_ops_log(&state.db, &auth.user_id, "user", "record_checkpoint",
183	        &format!("Recorded {} for fulfillment {}", req.checkpoint.as_str(), req.fulfillment_id));
184	
185	    Ok(Json(ApiSuccess { message: format!("Checkpoint {} recorded", req.checkpoint.as_str()) }))
186	}
