151	/// Deliver a single webhook call with HMAC signature.
152	async fn deliver_webhook(url: &str, secret: &str, event_type: &str, payload: &str) -> Result<u16, String> {
153	    // Compute HMAC signature
154	    let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).map_err(|e| e.to_string())?;
155	    mac.update(payload.as_bytes());
156	    let signature = hex::encode(mac.finalize().into_bytes());
157	
158	    let client = reqwest::Client::builder()
159	        .timeout(std::time::Duration::from_secs(10))
160	        .build()
161	        .map_err(|e| e.to_string())?;
162	
163	    let resp = client
164	        .post(url)
165	        .header("Content-Type", "application/json")
166	        .header("X-Webhook-Event", event_type)
167	        .header("X-Webhook-Signature", &signature)
168	        .body(payload.to_string())
169	        .send()
170	        .await
171	        .map_err(|e| e.to_string())?;
172	
173	    Ok(resp.status().as_u16())
174	}
