176	/// Check if a URL is on a local/private network.
177	fn is_local_url(url: &str) -> bool {
178	    let lower = url.to_lowercase();
179	    lower.contains("localhost")
180	        || lower.contains("127.0.0.1")
181	        || lower.contains("10.")
182	        || lower.contains("192.168.")
183	        || lower.contains("172.16.")
184	        || lower.contains("172.17.")
185	        || lower.contains("172.18.")
186	        || lower.contains("172.19.")
187	        || lower.contains("172.2")
188	        || lower.contains("172.30.")
189	        || lower.contains("172.31.")
190	        || lower.starts_with("http://[::1]")
191	        || lower.contains(".local")
192	}
