1	use aes_gcm::{
2	    aead::{Aead, KeyInit},
3	    Aes256Gcm, Nonce,
4	};
5	use rand::Rng;
6	use base64::{engine::general_purpose::STANDARD, Engine};
7	use std::path::Path;
8	
9	const KEY_FILE: &str = "data/encryption.key";
10	
11	/// Load or generate the application encryption key (32 bytes for AES-256).
12	pub fn load_or_create_key() -> [u8; 32] {
13	    let path = Path::new(KEY_FILE);
14	    if path.exists() {
15	        let data = std::fs::read(path).expect("Failed to read encryption key file");
16	        let mut key = [0u8; 32];
17	        key.copy_from_slice(&data[..32]);
18	        key
19	    } else {
20	        let key: [u8; 32] = rand::thread_rng().gen();
21	        if let Some(parent) = path.parent() {
22	            std::fs::create_dir_all(parent).ok();
23	        }
24	        std::fs::write(path, key).expect("Failed to write encryption key file");
25	        key
26	    }
27	}
28	
29	/// Encrypt plaintext using AES-256-GCM. Returns base64(nonce || ciphertext).
30	pub fn encrypt(plaintext: &str, key: &[u8; 32]) -> Result<String, String> {
31	    let cipher = Aes256Gcm::new_from_slice(key).map_err(|e| e.to_string())?;
32	    let nonce_bytes: [u8; 12] = rand::thread_rng().gen();
33	    let nonce = Nonce::from_slice(&nonce_bytes);
34	
35	    let ciphertext = cipher
36	        .encrypt(nonce, plaintext.as_bytes())
37	        .map_err(|e| e.to_string())?;
38	
39	    let mut combined = nonce_bytes.to_vec();
40	    combined.extend_from_slice(&ciphertext);
41	    Ok(STANDARD.encode(&combined))
42	}
43	
44	/// Decrypt base64(nonce || ciphertext) using AES-256-GCM.
45	pub fn decrypt(encoded: &str, key: &[u8; 32]) -> Result<String, String> {
46	    let combined = STANDARD.decode(encoded).map_err(|e| e.to_string())?;
47	    if combined.len() < 13 {
48	        return Err("Ciphertext too short".into());
49	    }
50	
51	    let (nonce_bytes, ciphertext) = combined.split_at(12);
52	    let cipher = Aes256Gcm::new_from_slice(key).map_err(|e| e.to_string())?;
53	    let nonce = Nonce::from_slice(nonce_bytes);
54	
55	    let plaintext = cipher
56	        .decrypt(nonce, ciphertext)
57	        .map_err(|e| e.to_string())?;
58	
59	    String::from_utf8(plaintext).map_err(|e| e.to_string())
60	}
