248	    let q = if parts.is_empty() { String::new() } else { format!("?{}", parts.join("&")) };
249	    let mut req = Request::get(&format!("{}/admin/export/csv{}", BASE, q));
250	    req = req.header("Authorization", &format!("Bearer {}", token));
