/// If the current UTC time is within the user's DND window, the notification is silently dropped.
pub fn create_notification(db: &DbPool, id: &str, user_id: &str, title: &str, body: &str) -> SqlResult<()> {
    let conn = db.lock();
    // Check DND
    let dnd: Option<(String, String)> = conn.query_row(
        "SELECT dnd_start, dnd_end FROM users WHERE id = ?1",
        params![user_id],
        |row| Ok((row.get(0)?, row.get(1)?)),
    ).ok();
    if let Some((start_str, end_str)) = dnd {
        let now = chrono::Utc::now().format("%H:%M").to_string();
        if is_within_dnd(&now, &start_str, &end_str) {
            return Ok(()); // Silently drop during DND
        }
    }
    conn.execute(
        "INSERT INTO notifications (id, user_id, title, body) VALUES (?1, ?2, ?3, ?4)",
        params![id, user_id, title, body],
    )?;
    Ok(())
}

/// Check if `now` (HH:MM) falls within a DND window.
/// Handles overnight windows like 21:00-07:00.
fn is_within_dnd(now: &str, start: &str, end: &str) -> bool {
    if start <= end {
        // Same-day window, e.g. 09:00-17:00
        now >= start && now < end
    } else {
        // Overnight window, e.g. 21:00-07:00
        now >= start || now < end
    }
}"}

